-- ============================================================================
-- SECTION 4 : BOOKS + AUTHORS
-- Covers:
-- Q17, Q28, Q43
-- ============================================================================

CREATE TABLE authors (
    author_id INT PRIMARY KEY,
    author_name VARCHAR(50),
    country VARCHAR(50)
);

CREATE TABLE books (
    book_id INT PRIMARY KEY,
    title VARCHAR(100),
    price DECIMAL(10,2),
    category VARCHAR(50),
    author_id INT,
    FOREIGN KEY(author_id) REFERENCES authors(author_id)
);

