-- ============================================================================

CREATE TABLE movies (
    movie_id INT PRIMARY KEY,
    movie_name VARCHAR(50)
);

CREATE TABLE ratings (
    rating_id INT PRIMARY KEY,
    movie_id INT,
    user_name VARCHAR(50),
    stars INT,
    FOREIGN KEY(movie_id) REFERENCES movies(movie_id)
);

